// server/db.ts
import { Pool } from "pg";
import { drizzle } from "drizzle-orm/node-postgres";
import "dotenv/config";
function buildPoolConfig(connectionString) {
  const url = new URL(connectionString);
  const isLocalDatabase = url.hostname === "localhost" || url.hostname === "127.0.0.1";
  const useSsl = !isLocalDatabase || url.searchParams.get("sslmode") === "require";
  return {
    connectionString: url.toString(),
    ssl: useSsl ? { rejectUnauthorized: false } : void 0
  };
}
var primaryPoolConfig, pool, db, readPool, dbRead;
var init_db = __esm({
  "server/db.ts"() {
    "use strict";
    init_diploy_core();
    init_schema();
    if (!process.env.DATABASE_URL) {
      throw new Error(
        "DATABASE_URL must be set. Did you forget to provision a database?"
      );
    }
    primaryPoolConfig = buildPoolConfig(process.env.DATABASE_URL);
    pool = new Pool({
      ...primaryPoolConfig,
      max: parseInt(process.env.DB_POOL_MAX || "25", 10),
      idleTimeoutMillis: 3e4,
      connectionTimeoutMillis: 5e3,
      allowExitOnIdle: true
    });
    pool.on("error", (err) => {
      console.error(`[${DIPLOY_BRAND}] Unexpected database pool error:`, err.message);
    });
    db = drizzle(pool, { schema: schema_exports });
    readPool = process.env.DATABASE_READ_URL ? new Pool({
      ...buildPoolConfig(process.env.DATABASE_READ_URL),
      max: parseInt(process.env.DB_POOL_MAX || "25", 10),
      idleTimeoutMillis: 3e4,
      connectionTimeoutMillis: 5e3,
      allowExitOnIdle: true
    }) : pool;
    if (process.env.DATABASE_READ_URL) {
      readPool.on("error", (err) => {
        console.error(`[${DIPLOY_BRAND}] Unexpected read replica pool error:`, err.message);
      });
      console.log(`[${DIPLOY_BRAND}] Read replica database configured`);
    }
    dbRead = process.env.DATABASE_READ_URL ? drizzle(readPool, { schema: schema_exports }) : db;
  }
});

// server/repositories/user.repository.ts
import { eq, desc, and } from "drizzle-orm";
var UserRepository;
var init_user_repository = __esm({
  "server/repositories/user.repository.ts"() {
    "use strict";
    init_db();
    init_schema();
    UserRepository = class {
      async getById(id) {
        const [user] = await db.select().from(users).where(eq(users.id, id));
        return user || void 0;
      }
      async getByPermissions(id) {
        const [result] = await db.select({ permissions: users.permissions }).from(users).where(eq(users.id, id));
        return result?.permissions || [];
      }
      async getByUsername(username) {
        const [user] = await db.select().from(users).where(eq(users.username, username));
        return user || void 0;
      }
      async create(insertUser) {
        const [user] = await db.insert(users).values(insertUser).returning();
        return user;
      }
      async getAll() {
        return await db.select().from(users).orderBy(desc(users.createdAt));
      }
      async getTeamUsersCountByCreator(createdBy) {
        const result = await db.select().from(users).where(
          and(
            eq(users.createdBy, createdBy),
            eq(users.role, "team")
          )
        );
        return result.length;
      }
    };
  }
});

