      static async checkRateLimit(channelId, channelTier) {
        const now = Date.now();
        const windowMs = 1e3;
        const maxPerTier = {
          TIER_250: 1,
          TIER_1K: 4,
          TIER_10K: 80,
          TIER_100K: 500,
          UNLIMITED: 1e3
        };
        const tierStr = (channelTier || process.env.WHATSAPP_MESSAGING_TIER || "TIER_10K").toUpperCase();
        const max = maxPerTier[tierStr] ?? 80;
        if (!this._rateLimitWindows.has(channelId)) {
          this._rateLimitWindows.set(channelId, []);
        }
        const timestamps = this._rateLimitWindows.get(channelId);
        const cutoff = now - windowMs;
        const recent = timestamps.filter((t) => t > cutoff);
        this._rateLimitWindows.set(channelId, recent);
        if (recent.length >= max) {
          return false;
        }
        recent.push(now);
        this._rateLimitWindows.set(channelId, recent);
        return true;
      }
