import { z } from "zod";
function validateRequest(schema) {
  return (req, res, next) => {
    try {
      req.body = schema.parse(req.body);
      next();
    } catch (error) {
      if (error instanceof z.ZodError) {
        throw new AppError(400, `Validation error: ${error.errors.map((e) => e.message).join(", ")}`);
      }
      throw error;
    }
  };
}

