async function exportPDF(req, res) {
  const { type, channelId, days = "30" } = req.query;
  const doc = new PDFDocument();
  res.setHeader("Content-Type", "application/pdf");
  res.setHeader("Content-Disposition", `attachment; filename=analytics-report-${(/* @__PURE__ */ new Date()).toISOString().split("T")[0]}.pdf`);
  doc.pipe(res);
  doc.fontSize(20).text("WhatsApp Analytics Report", { align: "center" });
  doc.moveDown();
  doc.fontSize(12).text(`Generated on: ${(/* @__PURE__ */ new Date()).toLocaleDateString()}`, { align: "center" });
  doc.moveDown(2);
  if (type === "messages" || type === "all") {
    const daysNum = parseInt(days);
    const start = new Date(Date.now() - daysNum * 24 * 60 * 60 * 1e3);
    const conditions = [];
    if (channelId) {
      conditions.push(eq22(conversations.channelId, channelId));
    }
    conditions.push(gte4(messages.createdAt, start));
    const stats = await dbRead.select({
      totalMessages: count2(messages.id),
      totalOutbound: sql11`COUNT(CASE WHEN ${messages.direction} = 'outbound' THEN 1 END)`,
      totalInbound: sql11`COUNT(CASE WHEN ${messages.direction} = 'inbound' THEN 1 END)`,
      delivered: sql11`COUNT(CASE WHEN ${messages.direction} = 'outbound' AND ${messages.status} IN ('delivered', 'read') THEN 1 END)`,
      read: sql11`COUNT(CASE WHEN ${messages.direction} = 'outbound' AND ${messages.status} = 'read' THEN 1 END)`,
      failed: sql11`COUNT(CASE WHEN ${messages.direction} = 'outbound' AND ${messages.status} = 'failed' THEN 1 END)`
    }).from(messages).innerJoin(conversations, eq22(messages.conversationId, conversations.id)).where(and15(...conditions));
    const s = stats[0];
    const outbound = Number(s?.totalOutbound) || 0;
    const deliv = Number(s?.delivered) || 0;
    const readCount = Number(s?.read) || 0;
    const failCount = Number(s?.failed) || 0;
    const delivRate = outbound > 0 ? Math.min(deliv / outbound * 100, 100).toFixed(1) : "0.0";
    const readRatePdf = deliv > 0 ? Math.min(readCount / deliv * 100, 100).toFixed(1) : "0.0";
    const failRate = outbound > 0 ? Math.min(failCount / outbound * 100, 100).toFixed(1) : "0.0";
    doc.fontSize(16).text("Message Statistics", { underline: true });
    doc.moveDown();
    doc.fontSize(12);
    doc.text(`Total Messages: ${s?.totalMessages || 0}`);
    doc.text(`Outbound: ${outbound}`);
    doc.text(`Inbound: ${Number(s?.totalInbound) || 0}`);
    doc.text(`Delivered: ${deliv} (${delivRate}%)`);
    doc.text(`Read: ${readCount} (${readRatePdf}%)`);
    doc.text(`Failed: ${failCount} (${failRate}%)`);
    doc.moveDown(2);
  }
  if (type === "campaigns" || type === "all") {
    const campaignStats = await dbRead.select({
      totalCampaigns: count2(campaigns.id),
      totalSent: sql11`SUM(${campaigns.sentCount})`,
      totalDelivered: sql11`SUM(${campaigns.deliveredCount})`
    }).from(campaigns).where(channelId ? eq22(campaigns.channelId, channelId) : void 0);
    doc.fontSize(16).text("Campaign Statistics", { underline: true });
    doc.moveDown();
    doc.fontSize(12);
    doc.text(`Total Campaigns: ${campaignStats[0]?.totalCampaigns || 0}`);
    doc.text(`Total Sent: ${campaignStats[0]?.totalSent || 0}`);
    doc.text(`Total Delivered: ${campaignStats[0]?.totalDelivered || 0}`);
  }
  doc.end();
}
