async function startCampaignExecution(campaignId, overrideCampaign) {
  console.log(`[Campaign ${campaignId}] Received start request \u2014 queuing in background`);
  const campaign = overrideCampaign ?? await storage.getCampaign(campaignId);
  if (!campaign) {
    console.error(`[Campaign ${campaignId}] Campaign not found`);
    return;
  }
  if (campaign.status !== "active") {
    console.warn(`[Campaign ${campaignId}] Skipping \u2014 status is "${campaign.status}", expected "active"`);
    return;
  }
  await storage.updateCampaign(campaignId, { status: "queued" });
  setImmediate(() => {
    void _runCampaignQueuePopulation(campaignId, campaign).catch((err) => {
      console.error(`[Campaign ${campaignId}] Fatal error during queue population:`, err);
      storage.updateCampaign(campaignId, { status: "failed" }).catch(() => {
      });
    });
  });
}
