var getCurrencyGatewayMap = async (req, res) => {
  try {
    const providers = await db.select().from(paymentProviders).where(eq31(paymentProviders.isActive, true));
    const currencyMap = {};
    for (const provider of providers) {
      const currencies = Array.isArray(provider.supportedCurrencies) && provider.supportedCurrencies.length > 0 ? provider.supportedCurrencies : provider.providerKey === "razorpay" ? ["INR"] : ["USD"];
      for (const cur of currencies) {
        const code = cur.toUpperCase();
        if (!currencyMap[code]) currencyMap[code] = [];
        currencyMap[code].push({
          providerKey: provider.providerKey,
          providerId: provider.id,
          providerName: provider.name
        });
      }
    }
    const availableCurrencies = Object.keys(currencyMap).sort();
    res.status(200).json({
      success: true,
      data: {
        currencyMap,
        availableCurrencies,
        providers: providers.map((p) => ({
          id: p.id,
          name: p.name,
          providerKey: p.providerKey,
          supportedCurrencies: Array.isArray(p.supportedCurrencies) && p.supportedCurrencies.length > 0 ? p.supportedCurrencies : p.providerKey === "razorpay" ? ["INR"] : ["USD"]
        }))
      }
    });
  } catch (error) {
    res.status(500).json({ success: false, message: "Error fetching currency gateway map", error });
  }
};
