  try {
    const { id } = req.params;
    const { gateway } = req.body;
    const plan = await db.select().from(plans).where(eq34(plans.id, id)).limit(1);
    if (!plan.length) {
      return res.status(404).json({ success: false, message: "Plan not found" });
    }
    let result;
    if (gateway === "stripe") {
      result = await syncPlanToStripe(id);
    } else if (gateway === "razorpay") {
      result = await syncPlanToRazorpay(id);
    } else {
      result = await syncPlanToAllGateways(id);
    }
    res.status(200).json({ success: true, data: result });
  } catch (error) {
    res.status(500).json({
      success: false,
      message: `Error syncing plan to gateway: ${error.message}`
    });
  }
