// server/routes/auth.routes.ts
init_email_service();
init_schema();
var router2 = Router2();
var loginSchema = z6.object({
  username: z6.string().min(1, "Username is required"),
  password: z6.string().min(1, "Password is required")
});
router2.post("/login", validateRequest2(loginSchema), async (req, res) => {
  try {
    const { username, password } = req.body;
    const results = await db.select().from(users).where(eq37(users.username, username));
    console.log(results);
    const user = results[0];
    if (!user) {
      console.warn("User not found:", username);
      return res.status(401).json({ error: "Invalid username or password" });
    }
    if ((user.status || "").trim().toLowerCase() !== "active") {
      return res.status(403).json({ error: "Account is inactive. Please contact administrator." });
    }
    if (user.isEmailVerified === false) {
      return res.status(403).json({ error: "Email not verified. Please verify your email first." });
    }
    if (!user.password) {
      console.error("User has no password in DB:", user.id);
      return res.status(500).json({ error: "User record is invalid. Contact support." });
    }
    const isValidPassword = await bcrypt3.compare(password, user.password);
    if (!isValidPassword) {
      return res.status(401).json({ error: "Invalid username or password" });
    }
    await db.update(users).set({
      lastLogin: /* @__PURE__ */ new Date(),
      updatedAt: /* @__PURE__ */ new Date()
    }).where(eq37(users.id, user.id));
    try {
      await db.insert(userActivityLogs).values({
        userId: user.id,
        action: "login",
        entityType: "user",
        entityId: user.id,
        details: JSON.stringify({
          ipAddress: req.ip,
          userAgent: req.get("user-agent")
        }),
        ipAddress: req.ip,
        userAgent: req.get("user-agent")
      });
    } catch (logError) {
      console.error("Failed to log login activity:", logError);
    }
    if (!req.session) {
      console.error("Session not initialized");
      return res.status(500).json({ error: "Session not initialized" });
    }
    req.session.user = {
      id: user.id,
      username: user.username,
      email: user.email,
      firstName: user.firstName,
      lastName: user.lastName,
      role: user.role,
      permissions: resolveUserPermissions(user.role, user.permissions),
      avatar: user.avatar,
      createdBy: user.createdBy || ""
    };
    const { password: _, ...userData } = user;
    res.json({
      message: "Login successful",
      user: userData
    });
  } catch (error) {
    console.log("Error during login:", error);
    res.status(500).json({ error: "Login failed", message: error.message });
  }
});
router2.post("/logout", (req, res) => {
  const userId = req.session?.user?.id;
  if (userId) {
    db.insert(userActivityLogs).values({
      userId,
      action: "logout",
      entityType: "user",
      entityId: userId,
      details: {}
    }).catch(console.error);
  }
  req.session.destroy((err) => {
    if (err) {
      console.error("Error destroying session:", err);
      return res.status(500).json({ error: "Logout failed" });
    }
    res.clearCookie("connect.sid");
    res.json({ message: "Logout successful" });
  });
});
router2.get("/me", async (req, res) => {
  const user = req.session?.user;
  if (!user) {
    return res.status(401).json({ error: "Not authenticated" });
  }
  const [currentUser] = await db.select().from(users).where(eq37(users.id, user.id));
  if (!currentUser) {
    return res.status(404).json({ error: "User not found" });
  }
  const { password, ...userData } = currentUser;
  res.json(userData);
});
router2.get("/check", (req, res) => {
  const user = req.session?.user;
  res.json({ authenticated: !!user, user });
});
router2.get("/country-data", (req, res) => {
  res.json(country_default);
});
router2.post("/forgot-password", async (req, res) => {
  try {
    const { email } = req.body;
    if (!email) {
      return res.status(400).json({ error: "Email is required" });
    }
    const existingUser = await db.select().from(users).where(eq37(users.email, email));
    if (!existingUser.length) {
      return res.status(404).json({ error: "Email not registered" });
    }
    const userId = existingUser[0].id;
    const userName = existingUser[0].firstName;
    const recentOTPs = await db.select().from(otpVerifications).where(
      and25(
        eq37(otpVerifications.userId, userId),
        sql20`${otpVerifications.createdAt} > NOW() - INTERVAL '5 minutes'`
      )
    );
    if (recentOTPs.length >= 3) {
      return res.status(429).json({
        error: "Too many requests. Try again in 5 minutes."
      });
    }
    const otpCode = Math.floor(1e5 + Math.random() * 9e5).toString();
    const expiresAt = new Date(Date.now() + 5 * 60 * 1e3);
    await db.insert(otpVerifications).values({
      userId,
      otpCode,
      expiresAt,
      isUsed: false
    });
    try {
      await sendOTPEmail(email, otpCode, userName);
      console.log(`\u2709\uFE0F OTP sent to ${email}`);
    } catch (emailError) {
      console.error("\u26A0\uFE0F Failed to send OTP email:", emailError);
    }
    res.json({
      success: true,
      message: "Verification code sent to your email"
    });
  } catch (error) {
    console.error("Forgot password error:", error);
    res.status(500).json({ error: error.message || "Failed to process request" });
  }
});
router2.post("/reset-password", async (req, res) => {
  try {
    const { email, newPassword } = req.body;
    if (!email || !newPassword) {
      return res.status(400).json({ error: "Email and new password are required" });
    }
    const existingUser = await db.select().from(users).where(eq37(users.email, email)).limit(1);
    if (!existingUser.length) {
      return res.status(404).json({ error: "Email not registered" });
    }
    const userId = existingUser[0].id;
    const otpRecord = await db.select().from(otpVerifications).where(
      eq37(otpVerifications.userId, userId),
      eq37(otpVerifications.isUsed, false)
    ).limit(1);
    if (!otpRecord.length) {
      return res.status(400).json({ error: "Invalid or already used OTP" });
    }
    const hashedPassword = await bcrypt3.hash(newPassword, 10);
    await db.update(users).set({ password: hashedPassword }).where(eq37(users.id, userId));
    await db.delete(otpVerifications).where(eq37(otpVerifications.id, otpRecord[0].id));
    res.json({ success: true, message: "Password updated successfully" });
  } catch (error) {
    console.error("Reset password error:", error);
    res.status(500).json({ error: error.message || "Failed to reset password" });
  }
});
router2.post("/verify-otp", async (req, res) => {
  try {
    const { email, otpCode } = req.body;
    console.log("Request body:", req.body);
    if (!email || !otpCode) {
      return res.status(400).json({ error: "Email and OTP are required" });
    }
    const existingUser = await db.select().from(users).where(eq37(users.email, email)).limit(1);
    console.log("Found user:", existingUser);
    if (!existingUser.length) {
      return res.status(404).json({ error: "Email not registered" });
    }
    const userId = existingUser[0].id;
    const otpRecord = await db.select().from(otpVerifications).where(
      and25(
        eq37(otpVerifications.userId, userId),
        eq37(otpVerifications.otpCode, otpCode.toString()),
        eq37(otpVerifications.isUsed, false)
        // sql`${otpVerifications.expiresAt} > timezone('UTC', now())`
      )
    ).limit(1);
    console.log("OTP records found:", otpRecord);
    if (otpRecord.length) {
      console.log("OTP expires at:", otpRecord[0].expiresAt);
      console.log("Current time:", (/* @__PURE__ */ new Date()).toISOString());
    }
    if (!otpRecord.length) {
      return res.status(400).json({ error: "Invalid or expired OTP" });
    }
    await db.update(otpVerifications).set({ isUsed: true }).where(eq37(otpVerifications.id, otpRecord[0].id));
    res.json({ success: true, message: "OTP verified successfully" });
  } catch (error) {
    console.error("OTP verification error:", error);
    res.status(500).json({ error: error.message || "Failed to verify OTP" });
  }
});
setInterval(async () => {
  try {
    await db.delete(otpVerifications).where(
      sql20`${otpVerifications.expiresAt} < timezone('UTC', now())`
    );
  } catch (error) {
    console.error("[OTP Cleanup] Error:", error);
  }
}, 5 * 60 * 1e3);
