var processBase64Image = async (base64Data, type) => {
  if (!base64Data || !base64Data.includes("base64,")) {
    return base64Data;
  }
  try {
    const matches = base64Data.match(/^data:([A-Za-z-+\/]+);base64,(.+)$/);
    if (!matches || matches.length !== 3) {
      return null;
    }
    const mimeType = matches[1];
    const data = matches[2];
    let extension = "png";
    if (mimeType.includes("jpeg") || mimeType.includes("jpg")) {
      extension = "jpg";
    } else if (mimeType.includes("svg")) {
      extension = "svg";
    } else if (mimeType.includes("icon") || type === "favicon") {
      extension = "ico";
    }
    const filename = `${type}-${Date.now()}.${extension}`;
    const uploadPath = path5.join(process.cwd(), "uploads", filename);
    const uploadsDir = path5.join(process.cwd(), "uploads");
    if (!fs5.existsSync(uploadsDir)) {
      fs5.mkdirSync(uploadsDir, { recursive: true });
    }
    fs5.writeFileSync(uploadPath, data, "base64");
    return `/uploads/${filename}`;
  } catch (error) {
    console.error("Error processing base64 image:", error);
    return null;
  }
};
