// server/controllers/group.controller.ts
init_schema();
init_db();
import { eq as eq44, and as and31, sql as sql23 } from "drizzle-orm";
var createGroup = async (req, res) => {
  try {
    const user = req.session?.user;
    const { name, description, channelId } = req.body;
    if (!channelId) {
      return res.status(400).json({ error: "channelId is required" });
    }
    const [group] = await db.insert(groups).values({ name, description, createdBy: user?.id, channelId }).returning();
    res.json({ success: true, group });
  } catch (e) {
    const errorMsg = e instanceof Error ? e.message : "Something went wrong";
    res.status(500).json({ error: errorMsg });
  }
};
var getGroups = async (req, res) => {
  try {
    const user = req.session?.user;
    const { channelId } = req.query;
    if (!channelId) {
      if (user?.role === "superadmin") {
        const allData = await db.select().from(groups);
        return res.json({ success: true, groups: allData });
      }
      return res.status(400).json({ success: false, error: "channelId is required" });
    }
    const channelGroups = await db.select().from(groups).where(eq44(groups.channelId, String(channelId)));
    const groupsWithCounts = await Promise.all(
      channelGroups.map(async (group) => {
        const result = await db.select({ count: sql23`count(*)` }).from(contacts).where(
          and31(
            eq44(contacts.channelId, String(channelId)),
            sql23`${contacts.groups}::jsonb @> ${JSON.stringify([group.name])}::jsonb`
          )
        );
        return {
          ...group,
          contact_count: Number(result[0]?.count || 0)
        };
      })
    );
    return res.json({ success: true, groups: groupsWithCounts });
  } catch (e) {
    res.status(500).json({ success: false, error: e.message });
  }
};
var getGroupById = async (req, res) => {
  try {
    const { id } = req.params;
    const [group] = await db.select().from(groups).where(eq44(groups.id, id));
    if (!group) return res.status(404).json({ error: "Group not found" });
    res.json({ success: true, group });
  } catch (e) {
    const errorMsg = e instanceof Error ? e.message : "Something went wrong";
    res.status(500).json({ error: errorMsg });
  }
};
var updateGroup = async (req, res) => {
  try {
    const { id } = req.params;
    const { name, description } = req.body;
    const [updated] = await db.update(groups).set({ name, description }).where(eq44(groups.id, id)).returning();
    res.json({ success: true, updated });
  } catch (e) {
    const errorMsg = e instanceof Error ? e.message : "Something went wrong";
    res.status(500).json({ error: errorMsg });
  }
};
var deleteGroup = async (req, res) => {
  try {
    const { id } = req.params;
    const [deleted] = await db.delete(groups).where(eq44(groups.id, id)).returning();
    if (deleted) {
      const allContacts = await db.select().from(contacts).where(sql23`${contacts.groups}::jsonb @> ${JSON.stringify([deleted.name])}::jsonb`);
      for (const contact of allContacts) {
        const updatedGroups = (contact.groups || []).filter((g) => g !== deleted.name);
        await db.update(contacts).set({ groups: updatedGroups }).where(eq44(contacts.id, contact.id));
      }
    }
    res.json({ success: true, deleted });
  } catch (e) {
    const errorMsg = e instanceof Error ? e.message : "Something went wrong";
    res.status(500).json({ error: errorMsg });
  }
};
var addContactsToGroup = async (req, res) => {
  try {
    const { contactIds, groupName, channelId } = req.body;
    if (!contactIds?.length || !groupName || !channelId) {
      return res.status(400).json({ error: "contactIds, groupName, and channelId are required" });
    }
    const [group] = await db.select().from(groups).where(and31(eq44(groups.name, groupName), eq44(groups.channelId, channelId)));
    if (!group) {
      return res.status(404).json({ error: "Group not found in this channel" });
    }
    let updatedCount = 0;
    for (const contactId of contactIds) {
      const [contact] = await db.select().from(contacts).where(and31(eq44(contacts.id, contactId), eq44(contacts.channelId, channelId)));
      if (contact) {
        const currentGroups = contact.groups || [];
        if (!currentGroups.includes(groupName)) {
          await db.update(contacts).set({ groups: [...currentGroups, groupName] }).where(eq44(contacts.id, contactId));
          updatedCount++;
        }
      }
    }
    res.json({ success: true, updatedCount });
  } catch (e) {
    const errorMsg = e instanceof Error ? e.message : "Something went wrong";
    res.status(500).json({ error: errorMsg });
  }
};
var removeContactsFromGroup = async (req, res) => {
  try {
    const { contactIds, groupName, channelId } = req.body;
    if (!contactIds?.length || !groupName || !channelId) {
      return res.status(400).json({ error: "contactIds, groupName, and channelId are required" });
    }
    let updatedCount = 0;
    for (const contactId of contactIds) {
      const [contact] = await db.select().from(contacts).where(and31(eq44(contacts.id, contactId), eq44(contacts.channelId, channelId)));
      if (contact) {
        const currentGroups = contact.groups || [];
        if (currentGroups.includes(groupName)) {
          await db.update(contacts).set({ groups: currentGroups.filter((g) => g !== groupName) }).where(eq44(contacts.id, contactId));
          updatedCount++;
        }
      }
    }
    res.json({ success: true, updatedCount });
  } catch (e) {
    const errorMsg = e instanceof Error ? e.message : "Something went wrong";
    res.status(500).json({ error: errorMsg });
  }
};
var getGroupContactCount = async (req, res) => {
  try {
    const { channelId } = req.query;
    if (!channelId) {
      return res.status(400).json({ error: "channelId is required" });
    }
    const channelGroups = await db.select().from(groups).where(eq44(groups.channelId, String(channelId)));
    const counts = {};
    for (const group of channelGroups) {
      const result = await db.select({ count: sql23`count(*)` }).from(contacts).where(
        and31(
          eq44(contacts.channelId, String(channelId)),
          sql23`${contacts.groups}::jsonb @> ${JSON.stringify([group.name])}::jsonb`
        )
      );
      counts[group.name] = Number(result[0]?.count || 0);
    }
    res.json({ success: true, counts });
  } catch (e) {
    const errorMsg = e instanceof Error ? e.message : "Something went wrong";
    res.status(500).json({ error: errorMsg });
  }
};

